package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.QuoteMode;

class CSVFormatTest {

    @Test
    void testGetQuoteMode_Default() {
        CSVFormat format = CSVFormat.DEFAULT;
        QuoteMode quoteMode = format.getQuoteMode();
        assertNull(quoteMode, "Default CSVFormat should have null QuoteMode");
    }

    @Test
    void testGetQuoteMode_CustomNonNull() {
        QuoteMode customMode = QuoteMode.ALL;
        CSVFormat format = CSVFormat.DEFAULT.withQuoteMode(customMode);
        QuoteMode quoteMode = format.getQuoteMode();
        assertEquals(customMode, quoteMode, "QuoteMode should be the custom one set");
    }

    @Test
    void testGetQuoteMode_CustomNull() {
        CSVFormat format = CSVFormat.DEFAULT.withQuoteMode(null);
        QuoteMode quoteMode = format.getQuoteMode();
        assertNull(quoteMode, "QuoteMode should be null when explicitly set to null");
    }
}
